@page "/privacy"
@attribute [RenderModeAttribute(0)]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✓ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>How We Use Cookies</h2>
<p>
    This site uses cookies to improve your experience. By continuing to use this site,
    you agree to our use of cookies as described in this policy.
</p>

<h2>What Cookies We Use</h2>
<ul>
    <li><strong>Essential cookies</strong> – required for the site to function correctly.</li>
    <li><strong>Consent cookie</strong> – records whether you have accepted our cookie policy.</li>
</ul>

@code {
    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            HasConsented = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

