 <head>
     <meta charset="utf-8" />
     <meta name="viewport" content="width=device-width, initial-scale=1.0" />
     <base href="/" />
     <HeadOutlet @rendermode="PageRenderMode" />
 </head>

 <body>
     <Routes @rendermode="PageRenderMode" />
     <script src="_framework/blazor.web.js"></script>
 </body>

 </html>

 @code {
     [CascadingParameter]
     private HttpContext? HttpContext { get; set; }

     private IComponentRenderMode? PageRenderMode
     {
         get
         {
             // Check whether the matched page is decorated with [StaticSsrPage].
             // If so, render statically (return null) so HttpContext remains available.
             // Otherwise, use InteractiveServer for global interactivity.
             var endpoint = HttpContext?.GetEndpoint();
             if (endpoint?.Metadata.GetMetadata<StaticSsrPageAttribute>() is not null)
             {
                 return null;
             }

             return new InteractiveServerRenderMode();
         }
     }
 }

